<?php require __DIR__.'/includes/pawn_bootstrap.php';if(!pawn_permission($conn,'create')){http_response_code(403);die('Access denied.');}$theme=pawn_theme($conn,$businessId);$customers=[];$st=$conn->prepare("SELECT id,customer_code,customer_name,mobile,address_line1,city,state,pincode FROM customers WHERE business_id=? AND is_active=1 AND customer_type IN ('Pawn','All') ORDER BY customer_name");$st->bind_param('i',$businessId);$st->execute();$customers=$st->get_result()->fetch_all(MYSQLI_ASSOC);$st->close();$cats=[];$st=$conn->prepare('SELECT id,category_name,default_interest_percent FROM pawn_categories WHERE business_id=? AND is_active=1 ORDER BY category_name');$st->bind_param('i',$businessId);$st->execute();$cats=$st->get_result()->fetch_all(MYSQLI_ASSOC);$st->close();$metals=[];$st=$conn->prepare('SELECT id,metal_name FROM metals WHERE business_id=? AND is_active=1 ORDER BY metal_name');$st->bind_param('i',$businessId);$st->execute();$metals=$st->get_result()->fetch_all(MYSQLI_ASSOC);$st->close();$businessName=$_SESSION['business_name']??'Jewellery ERP';?>
<!doctype html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title><?=pawn_e($businessName)?> - New Pawn</title><?php include 'includes/links.php';include __DIR__.'/includes/pawn_styles.php';?></head><body><?php include 'includes/sidebar.php';?><main class="app-main"><?php include 'includes/nav.php';?><div class="content-wrap"><form class="pawn-card" id="pawnForm" enctype="multipart/form-data"><div class="pawn-head"><div><div class="pawn-title">New Pawn Entry</div><div class="small text-muted">Create a secured jewellery pledge.</div></div><a href="pawn-list.php" class="btn btn-light btn-sm">Back</a></div><input type="hidden" name="csrf_token" value="<?=pawn_e($pawnCsrf)?>"><div class="section"><div class="section-title">Customer & Loan</div><div class="row g-3"><div class="col-md-5"><label class="field-label">Customer *</label><select class="form-select" name="customer_id" required><option value="">Select customer</option><?php foreach($customers as $c):?><option value="<?=(int)$c['id']?>"><?=pawn_e($c['customer_code'].' - '.$c['customer_name'].' - '.$c['mobile'])?></option><?php endforeach?></select></div><div class="col-md-3"><label class="field-label">Pawn date *</label><input type="date" class="form-control" name="pawn_date" value="<?=date('Y-m-d')?>" required></div><div class="col-md-4"><label class="field-label">Category *</label><select class="form-select" name="pawn_category_id" id="cat" required><option value="">Select category</option><?php foreach($cats as $c):?><option value="<?=(int)$c['id']?>" data-rate="<?=pawn_e($c['default_interest_percent'])?>"><?=pawn_e($c['category_name'])?></option><?php endforeach?></select></div><div class="col-md-3"><label class="field-label">Principal amount *</label><input type="number" min="1" step="0.01" class="form-control" name="principal_amount" required></div><div class="col-md-3"><label class="field-label">Interest % *</label><input type="number" min="0" step="0.001" class="form-control" name="interest_percent" id="rate" required></div><div class="col-md-3"><label class="field-label">Interest period</label><select class="form-select" name="interest_period"><option>Monthly</option><option>Daily</option><option>Yearly</option></select></div><div class="col-md-3"><label class="field-label">Due date</label><input type="date" class="form-control" name="due_date"></div></div></div><div class="section"><div class="d-flex justify-content-between align-items-center mb-3"><div class="section-title mb-0">Pledged Items</div><button type="button" class="btn btn-light btn-sm" id="addItem"><i class="fa-solid fa-plus me-1"></i>Add item</button></div><div id="items"></div><template id="itemTpl"><div class="item-row"><div class="row g-2"><div class="col-md-2"><label class="field-label">Metal *</label><select class="form-select" name="metal_id[]" required><option value="">Select</option><?php foreach($metals as $m):?><option value="<?=(int)$m['id']?>"><?=pawn_e($m['metal_name'])?></option><?php endforeach?></select></div><div class="col-md-3"><label class="field-label">Description *</label><input class="form-control" name="item_description[]" required></div><div class="col-md-1"><label class="field-label">Qty</label><input type="number" step="0.001" class="form-control" name="quantity[]" value="1"></div><div class="col-md-1"><label class="field-label">Gross</label><input type="number" step="0.001" class="form-control gross" name="gross_weight[]" value="0"></div><div class="col-md-1"><label class="field-label">Stone</label><input type="number" step="0.001" class="form-control stone" name="stone_weight[]" value="0"></div><div class="col-md-1"><label class="field-label">Net</label><input type="number" step="0.001" class="form-control net" name="net_weight[]" value="0" readonly></div><div class="col-md-1"><label class="field-label">Purity</label><input type="number" step="0.0001" class="form-control" name="purity[]"></div><div class="col-md-1"><label class="field-label">Value</label><input type="number" step="0.01" class="form-control" name="estimated_value[]" value="0"></div><div class="col-md-1 d-flex align-items-end"><button type="button" class="btn btn-outline-danger btn-sm remove"><i class="fa-solid fa-trash"></i></button></div><div class="col-md-4"><label class="field-label">Item image</label><input type="file" class="form-control" name="item_image[]" accept="image/jpeg,image/png,image/webp"></div></div></div></template></div><div class="section"><label class="field-label">Remarks</label><textarea class="form-control" name="remarks" rows="3"></textarea></div><div class="section text-end"><button class="btn btn-theme" id="saveBtn"><i class="fa-solid fa-floppy-disk me-2"></i>Save Pawn</button></div></form><?php include 'includes/footer.php';?></div></main><?php include 'includes/script.php';?><script src="assets/js/script.js"></script><script>
(()=>{const box=document.getElementById('items'),tpl=document.getElementById('itemTpl'),f=document.getElementById('pawnForm'),btn=document.getElementById('saveBtn');function add(){box.append(tpl.content.cloneNode(true))}add();document.getElementById('addItem').onclick=add;box.addEventListener('click',e=>{if(e.target.closest('.remove')&&box.children.length>1)e.target.closest('.item-row').remove()});box.addEventListener('input',e=>{const row=e.target.closest('.item-row');if(!row)return;row.querySelector('.net').value=Math.max(0,(parseFloat(row.querySelector('.gross').value)||0)-(parseFloat(row.querySelector('.stone').value)||0)).toFixed(3)});document.getElementById('cat').onchange=e=>{document.getElementById('rate').value=e.target.selectedOptions[0]?.dataset.rate||''};f.onsubmit=async e=>{e.preventDefault();const old=btn.innerHTML;btn.disabled=true;btn.innerHTML='Saving...';try{const r=await fetch('api/pawn-save.php',{method:'POST',body:new FormData(f),credentials:'same-origin'});const j=await r.json();if(!j.success)throw new Error(j.message);location.href='pawn-view.php?id='+j.id}catch(x){alert(x.message)}finally{btn.disabled=false;btn.innerHTML=old}}})();
</script></body></html>
